import {refInput} from "@hoge1e3/ref-input";
import {id as gid} from "@hoge1e3/dom-id";
import {update} from "@hoge1e3/dom-updater";
const sym_events="__events";
const sym_id="__refid";
const sym_objid=Symbol("__objid");
//const sym_objid_dom=Symbol("__objid_dom");
