function objid(o){
  if(o[sym_objid])return o[sym_objid];
  o[sym_objid]=gid();
  return o[sym_objid];
}
export function im(domid,ref,render){
  if(!domid)throw new Error("id must be specified");
  domid+="";
  const value=ref.value;
  if(typeof render!=="function"){
    const dom=render;
    dom.id=domid;
    dom.setAttribute("data-version",objid(value));
    return refInput(ref,render);
  }
  const dst=document.getElementById(domid);
  if(dst.getAttribute("data-version")===
    objid(value)){
    return dst;
  }
  const dom=render(value);
  const events=(
    r[sym_events]=
    r[sym_events]||
    new Set());
  dom.id=domid;
  dom.setAttribute("data-version",objid(value));
  if(!events.has(domid)){
    ref.on("change",(value)=>{
      const dst=document.getElementById(domid);
      if(dom.getAttribute("data-version")
      ===objid(value))return ;
      const src=render(ref.value);
      dom.id=domid;
      
      /*if(src.id!==domid){
        throw new Error("id not match");
      }*/
      update(dst,src);
    });
  }
  return dom;
}
export function r(ref,render){
  if(typeof render!=="function"){
    return refInput(ref,render);
  }
  const dom=render(ref.value);
  const events=(
    r[sym_events]=
    r[sym_events]||
    new Set());
  //const domid=id+"-"+refid(ref);
  const domid=dom.id;
  if(!domid)throw new Error("id must be specified");
  //dom.id=domid;
  if(!events.has(domid)){
    ref.on("change",(value)=>{
      const dst=document.getElementById(domid);
      const src=render(ref.value);
      if(src.id!==domid){
        throw new Error("id not match");
      }
      update(dst,src);
    });
  }
  return dom;
}
let refc=Math.floor(performance.now());
export function refid(r){
  r[sym_id]=r[sym_id]||
  "ref"+(refc++);
  return r[sym_id];
}